import type { Question, Subject } from '../types'

function q(
  id: string,
  question: string,
  options: string[],
  answer: string,
  explanation: string,
  subject: Subject,
  passage?: string
): Question {
  return { id, question, options, answer, explanation, subject, passage }
}

