export function getQuestions(subject: string): Question[] {
  const bank = QUESTION_BANK[subject]
  if (bank) return [...bank]
  return MATHEMATICS.map((q, i) => ({
    ...q,
    id: `${subject.slice(0, 3).toLowerCase()}${i}`,
    question: `[${subject}] ${q.question}`,
    subject: subject as Subject,
  }))
}
